4064							// 构造最小的 FileTreeNode 以复用右键菜单,保持修改清单和文件树相同的打开/定位入口。
4065							const fakeNode: FileTreeNode = {
4066								name: fileName,
4067								path: file.path,
4068								relativePath: file.path,
4069								type: "file",
4070							};
4071							return (
4072								<div
4073									key={file.path}
4074									className={`modified-file-row${isRunning ? " running" : ""}`}
4075									title={file.path}
4076									onContextMenu={(e) => {
4077										e.preventDefault();
4078										props.onFileContextMenu(fakeNode, e.clientX, e.clientY);
4079									}}
4080									onClick={() => props.onDiffFile?.(file.path, file.originalContent, file.content)}
4081								>
4082									<span
4083										className={`modified-file-icon${isRunning ? "" : " done"}`}
4084									>
4085										{file.toolName === "git"
4086											? gitStatusIcon(file.status)
4087											: isRunning
4088												? "◌"
4089												: "✓"}
4090									</span>
4091									<span className="modified-file-name">{fileName}</span>
4092									{file.toolName === "git" && file.status !== "deleted" && (
4093										<span className="modified-file-lines">{file.status === "added" ? "新" : "改"}</span>
4094									)}
4095									{file.toolName !== "git" && Boolean(file.changedLines) && (
4096										<span className="modified-file-lines">
4097											{t("drawer.changedLines", {
4098												count: file.changedLines ?? 0,
4099											})}
4100										</span>
4101									)}
4102									<span className="modified-file-tool">{file.toolName}</span>
4103								</div>
4104							);
4105						})}
4106						{latestModifiedFiles.length > MODIFIED_FILES_PREVIEW_LIMIT && (
4107							<button
4108								className="modified-files-toggle"
4109								type="button"
4110								onClick={handleToggleModifiedFiles}
4111							>
4112								{modifiedFilesExpanded
4113									? t("common.collapse")
4114									: t("drawer.moreFiles", { count: hiddenModifiedFileCount })}
4115							</button>
4116						)}
4117					</div>
4118				)}
4119				{props.files.map((node) => (
4120					<FileNode
4121						key={node.path}
4122						node={node}
4123						expandedDirs={props.expandedDirs}
4124						onToggleDirectory={props.onToggleDirectory}
4125						onFileContextMenu={props.onFileContextMenu}
4126						onOpenFile={props.onOpenFile}
4127						onViewFile={props.onViewFile}
4128						onDiffFile={props.onDiffFile}
4129						gitStatuses={gitStatusMap}
4130					/>
4131				))}
4132			</div>
4133		);
4134	}
4135	
4136	const SESSION_FILE_SUMMARY_COLLAPSED_KEY_PREFIX =
4137		"pid:session-file-summary-collapsed:";
4138	const SESSION_FILE_SUMMARY_FILE_LIST_EXPANDED_KEY_PREFIX =
4139		"pid:session-file-summary-file-list-expanded:";
4140	
4260						)}
4261					</>
4262				)}
4263			</section>
4264		);
4265	}
4266	
4267	function fileIconElement(name: string, isDirectory: boolean, isExpanded: boolean) {
4268		if (isDirectory) {
4269			return isExpanded ? <FolderOpen size={16} /> : <Folder size={16} />;
4270		}
4271		try {
4272			const { svg, colorName } = getFileIconSeti(name);
4273			const color = getFileIconColor(colorName);
4274			return (
4275				<span className="file-node-seti-icon" style={{ color }}
4276					dangerouslySetInnerHTML={{ __html: svg }} />
4277			);
4278		} catch {
4279			return <FileText size={15} />;
4280		}
4281	}
4282	
4283	function FileNode(props: {
4284		node: FileTreeNode;
4285		expandedDirs: Set<string>;
4286		onToggleDirectory: (path: string) => void;
4287		onFileContextMenu: (node: FileTreeNode, x: number, y: number) => void;
4288		onOpenFile?: (path: string) => void;
4289		onViewFile?: (path: string) => void;
4290		onDiffFile?: (path: string) => void;
4291		gitStatuses?: Map<string, string>;
4292		depth?: number;
4293	}) {
4294		const { node, expandedDirs, onToggleDirectory, depth = 0, gitStatuses } = props;
4295		const expanded = expandedDirs.has(node.path);
4296		const typeLabel = getFileTypeLabel(node.name);
4297		const gitStatus = gitStatuses?.get(node.path);
4298		const rowStyle = { "--file-depth-offset": `${depth * 16}px` } as CSSProperties;
4299		const menu = (event: React.MouseEvent) => {
4300			event.preventDefault();
4301			props.onFileContextMenu(node, event.clientX, event.clientY);
4302		};
4303		if (node.type === "file")
4304			return (
4305				<div className="file-node" style={rowStyle}>
4306					<button className="file file-node-row" style={rowStyle}
4307						title={`${node.relativePath}\n${typeLabel}`}
4308						onClick={() => props.onViewFile?.(node.path)}
4309						onContextMenu={menu}>
4310						<span className="file-node-icon">
4311							{fileIconElement(node.name, false, false)}
4312							{gitStatus && <span className={`file-node-git-badge git-${gitStatus}`} />}
4313						</span>
4314						<span className="file-node-name">{node.name}</span>
4315						<span className="file-node-type-label">{typeLabel}</span>
4316					</button>
4317				</div>
4318			);
4319		return (
4320			<div className="file-node" style={rowStyle}>
4321				<button className="directory file-node-row" style={rowStyle}
4322					onClick={() => onToggleDirectory(node.path)}
4323					onContextMenu={menu}
4324					title={`${node.relativePath}\n${typeLabel}`}>
4325					<span className="file-node-icon">
4326						{fileIconElement(node.name, true, expanded)}
4327					</span>
4328					<span className="file-node-name">{node.name}</span>
4329				</button>
4330				{expanded && node.children && node.children.length > 0 && (
4331					<div className="file-children">
4332						{node.children.map((child) => (
4333							<FileNode key={child.path} node={child}
4334								expandedDirs={expandedDirs}
4335								onToggleDirectory={onToggleDirectory}
4336								onFileContextMenu={props.onFileContextMenu}
4337								onOpenFile={props.onOpenFile}
4338								onViewFile={props.onViewFile}
4339								onDiffFile={props.onDiffFile}
4340								gitStatuses={gitStatuses}
4341								depth={depth + 1} />
4342						))}
4343					</div>
4344				)}
4345			</div>
4346		);
4347	}
4348	
4349	function gitStatusIcon(status: string): string {
4350		switch (status) {
4351			case "added":
4352				return "+";
4353			case "deleted":
4354				return "×";
4355			case "renamed":
4356				return "→";
4357			default:
4358				return "~";
4359		}
4360	}

