 1	import rawDefinitions from "./definitions.json";
 2	import rawIcons from "./icons.json";
 3	
 4	export type SetiIconColor =
 5	  | "blue"
 6	  | "grey"
 7	  | "grey-light"
 8	  | "green"
 9	  | "orange"
10	  | "pink"
11	  | "purple"
12	  | "red"
13	  | "white"
14	  | "yellow"
15	  | "ignore";
16	
17	type IconDetails = [icon: string, color: SetiIconColor];
18	type SetiDefinitions = {
19	  files: Record<string, IconDetails>;
20	  extensions: Record<string, IconDetails>;
21	  partials: Array<[needle: string, details: IconDetails]>;
22	  default: IconDetails;
23	};
24	
25	const definitions = rawDefinitions as SetiDefinitions;
26	const icons = rawIcons as Record<string, string>;
27	const hasOwn = (record: object, key: string) =>
28	  Object.prototype.hasOwnProperty.call(record, key);
29	
30	function getDetails(fileName: string): IconDetails {
31	  if (hasOwn(definitions.files, fileName)) return definitions.files[fileName];
32	
33	  // Multi-part mappings such as `.spec.tsx` take priority before the final `.tsx` suffix.
34	  for (let dot = fileName.indexOf("."); dot !== -1; dot = fileName.indexOf(".", dot + 1)) {
35	    const extension = fileName.slice(dot);
36	    if (hasOwn(definitions.extensions, extension)) {
37	      return definitions.extensions[extension];
38	    }
39	  }
40	
41	  for (const [needle, details] of definitions.partials) {
42	    if (fileName.includes(needle)) return details;
43	  }
44	  return definitions.default;
45	}
46	
47	/** Returns a trusted, bundled Seti SVG and its semantic color name. */
48	export function getSetiIcon(fileName: string): { svg: string; color: SetiIconColor } {
49	  const [iconName, color] = getDetails(fileName);
50	  return {
51	    svg: icons[iconName] ?? icons[definitions.default[0]],
52	    color,
53	  };
54	}

